import { calculatePartnerPayout } from "./calculatePartnerPayout";

// ─── AC1 + AC2: Core formula ───────────────────────────────────────────────
describe("calculatePartnerPayout — core formula (AC1, AC2)", () => {
  it("computes platformFeeAmount as transactionAmount * platformFeePercentage", () => {
    // $200, 10% platform fee → fee = $20, net = $180, 50% share → $90.00
    expect(calculatePartnerPayout(200, 0.1, 0.5)).toBe(90.0);
  });

  it("computes partnerPayout as (transactionAmount - platformFee) * partnerShare", () => {
    // $1000, 20% platform fee → fee = $200, net = $800, 80% share → $640.00
    expect(calculatePartnerPayout(1000, 0.2, 0.8)).toBe(640.0);
  });
});

// ─── AC3: Canonical example ────────────────────────────────────────────────
describe("calculatePartnerPayout — canonical example (AC3)", () => {
  it("returns $66.50 for $100 transaction, 5% fee, 70% partner share", () => {
    expect(calculatePartnerPayout(100, 0.05, 0.7)).toBe(66.5);
  });
});

// ─── AC4: Floor rounding ───────────────────────────────────────────────────
describe("calculatePartnerPayout — floor rounding (AC4)", () => {
  it("floors fractional cents — does NOT round half-up", () => {
    // $100, 0% fee → net $100, 1/3 share → $33.333... → should be $33.33
    expect(calculatePartnerPayout(100, 0, 1 / 3)).toBe(33.33);
  });

  it("floors when raw result is X.999... cents", () => {
    // $10, 0% fee, share that yields $6.666... → $6.66
    expect(calculatePartnerPayout(10, 0, 2 / 3)).toBe(6.66);
  });

  it("retains exact value when result is already a whole cent", () => {
    // $50, 0% fee, 50% share → $25.00 exactly
    expect(calculatePartnerPayout(50, 0, 0.5)).toBe(25.0);
  });

  it("floors — does not round a .5-cent fraction up", () => {
    // Construct a case where naive round-half-up would differ from floor:
    // $100, 0% fee, 37.5% share → $37.50 (exact, floor = round here)
    // Better: $1, 0% fee, share = 0.005 → $0.005 → floor = $0.00
    expect(calculatePartnerPayout(1, 0, 0.005)).toBe(0.0);
  });
});

// ─── AC5: Zero transaction amount ─────────────────────────────────────────
describe("calculatePartnerPayout — zero transaction (AC5)", () => {
  it("returns 0 when transactionAmount is 0", () => {
    expect(calculatePartnerPayout(0, 0.05, 0.7)).toBe(0);
  });

  it("returns 0 when transactionAmount is 0 regardless of fee/share values", () => {
    expect(calculatePartnerPayout(0, 0, 0)).toBe(0);
    expect(calculatePartnerPayout(0, 1.0, 1.0)).toBe(0);
  });
});

// ─── Boundary / additional coverage ───────────────────────────────────────
describe("calculatePartnerPayout — boundary cases", () => {
  it("returns 0 when partnerSharePercentage is 0", () => {
    expect(calculatePartnerPayout(100, 0.05, 0)).toBe(0);
  });

  it("returns full net amount when partnerSharePercentage is 1.0", () => {
    // $100, 5% fee → net $95, 100% share → $95.00
    expect(calculatePartnerPayout(100, 0.05, 1.0)).toBe(95.0);
  });

  it("returns 0 when platformFeePercentage is 1.0 (fee consumes entire transaction)", () => {
    // $100, 100% fee → net $0, any share → $0
    expect(calculatePartnerPayout(100, 1.0, 0.7)).toBe(0);
  });

  it("handles small sub-dollar transactions correctly", () => {
    // $0.10, 10% fee → net $0.09, 50% share → $0.045 → floor → $0.04
    expect(calculatePartnerPayout(0.1, 0.1, 0.5)).toBe(0.04);
  });

  it("handles large transaction amounts without overflow", () => {
    // $1,000,000, 5% fee → net $950,000, 70% share → $665,000
    expect(calculatePartnerPayout(1_000_000, 0.05, 0.7)).toBe(665_000);
  });
});

